package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;
import org.mockito.Mockito;

import java.lang.reflect.Field;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        // Use the DEFAULT instance as base
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testIsCommentMarkerSet_WhenCommentMarkerIsNull() throws Exception {
        // commentMarker is private final, so create a new instance with commentMarker null
        CSVFormat format = createCSVFormatWithCommentMarker(null);
        assertFalse(format.isCommentMarkerSet());
    }

    @Test
    public void testIsCommentMarkerSet_WhenCommentMarkerIsSet() throws Exception {
        Character commentChar = '#';
        CSVFormat format = createCSVFormatWithCommentMarker(commentChar);
        assertTrue(format.isCommentMarkerSet());
    }

    // Helper method to create CSVFormat instance with specified commentMarker via reflection
    private CSVFormat createCSVFormatWithCommentMarker(Character commentMarker) throws Exception {
        // Use reflection to access private constructor
        java.lang.reflect.Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class, Character.class, QuoteMode.class, Character.class, Character.class,
                boolean.class, boolean.class, String.class, String.class, Object[].class,
                String[].class, boolean.class, boolean.class, boolean.class, boolean.class,
                boolean.class, boolean.class);
        constructor.setAccessible(true);
        // Provide values for all parameters, setting commentMarker as desired
        return constructor.newInstance(
                ',',               // delimiter
                '"',               // quoteChar
                null,              // quoteMode
                commentMarker,     // commentStart
                null,              // escape
                false,             // ignoreSurroundingSpaces
                true,              // ignoreEmptyLines
                "\r\n",            // recordSeparator
                null,              // nullString
                null,              // headerComments
                null,              // header
                false,             // skipHeaderRecord
                false,             // allowMissingColumnNames
                false,             // ignoreHeaderCase
                false,             // trim
                false,             // trailingDelimiter
                false              // autoFlush
        );
    }
}
